def canVisitAllRooms(self, rooms: List[List[int]]) -> bool:
    n = len(rooms)
    visited = [False] * n
    key_count = [len(room) for room in rooms]

    for i in range(n):
        if not visited[i]:
            for key in rooms[i]:
                for j in range(key_count[key]):
                    visited[key] = True

    return all(visited)

